// ✅ FIXED - Canvas Particle Background (No syntax errors)
const ParticleBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return

    const ctx = canvas.getContext('2d')
    if (!ctx) return

    let animationFrameId: number
    const particles: any[] = []
    let mouseX = 0
    let mouseY = 0
    let time = 0

    const resizeCanvas = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resizeCanvas()
    window.addEventListener('resize', resizeCanvas)

    class Particle {
      x: number
      y: number
      vx: number
      vy: number
      size: number
      opacity: number
      hue: number
      glow: number

      constructor() {
        this.x = Math.random() * canvas.width
        this.y = Math.random() * canvas.height
        this.vx = (Math.random() - 0.5) * 0.8
        this.vy = (Math.random() - 0.5) * 0.8
        this.size = Math.random() * 2 + 1
        this.opacity = Math.random() * 0.5 + 0.2
        this.hue = Math.random() * 60 + 200
        this.glow = Math.random() * 15 + 5
      }

      update() {
        const dx = mouseX - this.x
        const dy = mouseY - this.y
        const dist = Math.sqrt(dx * dx + dy * dy)
        if (dist < 150) {
          this.vx += dx * 0.01
          this.vy += dy * 0.01
        }

        this.x += this.vx
        this.y += this.vy
        this.vx *= 0.96
        this.vy *= 0.96

        if (this.x > canvas.width || this.x < 0) this.vx *= -1
        if (this.y > canvas.height || this.y < 0) this.vy *= -1

        this.opacity += Math.sin(time * 0.01) * 0.005
        this.hue += 0.2
      }

      draw() {
        ctx.save()
        ctx.globalAlpha = this.opacity
        ctx.shadowColor = `hsla(${this.hue}, 70%, 60%, 0.8)`
        ctx.shadowBlur = this.glow
        ctx.fillStyle = `hsla(${this.hue}, 70%, 60%, ${this.opacity})`
        ctx.beginPath()
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2)
        ctx.fill()
        ctx.restore()
      }
    }

    for (let i = 0; i < 120; i++) {
      particles.push(new Particle())
    }

    const handleMouseMove = (e: MouseEvent) => {
      mouseX = e.clientX
      mouseY = e.clientY
    }
    window.addEventListener('mousemove', handleMouseMove)

    const animate = () => {
      ctx.fillStyle = 'rgba(15, 15, 35, 0.1)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      const gridSize = 50
      time += 0.05
      for (let x = 0; x < canvas.width; x += gridSize) {
        for (let y = 0; y < canvas.height; y += gridSize) {
          const pulse = Math.sin(time + x * 0.01 + y * 0.01) * 0.5 + 0.5
          ctx.strokeStyle = `rgba(120, 119, 198, ${0.02 * pulse})`
          ctx.lineWidth = 1
          ctx.strokeRect(x, y, gridSize, gridSize)
        }
      }

      for (let i = 0; i < particles.length; i++) {
        particles[i].update()
        particles[i].draw()

        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x
          const dy = particles[i].y - particles[j].y
          const distance = Math.sqrt(dx * dx + dy * dy)
          
          if (distance < 120) {
            ctx.strokeStyle = `rgba(120, 119, 198, ${0.3 * (1 - distance / 120)})`
            ctx.lineWidth = 1 * (1 - distance / 120)
            ctx.beginPath()
            ctx.moveTo(particles[i].x, particles[i].y)
            ctx.lineTo(particles[j].x, particles[j].y)
            ctx.stroke()
          }
        }
      }

      animationFrameId = requestAnimationFrame(animate)
    }
    animate()

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('resize', resizeCanvas)
      if (animationFrameId) cancelAnimationFrame(animationFrameId)
    }
  }, [])

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 z-0 pointer-events-none"
      style={{ 
        background: 'linear-gradient(135deg, #0f0f23 0%, #1a1a3e 30%, #2d1b69 70%, #1a0033 100%)'
      }}
    />
  )
}

