// Stats Counter
const StatsCounter = () => {
  const [stats, setStats] = useState({ projects: 0, clients: 0, industries: 0, satisfaction: 0 })
  const hasAnimated = useRef(false)

  useEffect(() => {
    if (hasAnimated.current) return
    
    const targets = [200, 50, 15, 98]
    let startTime: number

    const animateCounters = (currentTime: number) => {
      if (!startTime) startTime = currentTime
      const elapsed = currentTime - startTime
      const progress = Math.min(elapsed / 2000, 1)

      setStats({
        projects: Math.floor(progress * targets[0]),
        clients: Math.floor(progress * targets[1]),
        industries: Math.floor(progress * targets[2]),
        satisfaction: Math.floor(progress * targets[3])
      })

      if (progress < 1) {
        requestAnimationFrame(animateCounters)
      } else {
        hasAnimated.current = true
      }
    }

    requestAnimationFrame(animateCounters)
  }, [])

  const statItems = [
    { value: `${stats.projects}+`, label: "Projects Completed" },
    { value: `${stats.clients}+`, label: "Happy Clients" },
    { value: `${stats.industries}+`, label: "Industries Served" },
    { value: `${stats.satisfaction}%`, label: "Client Satisfaction" },
  ]

  return (
    <div className="grid grid-cols-2 gap-8 lg:grid-cols-4">
      {statItems.map((stat, index) => (
        <div key={stat.label} className="text-center group">
          <div className="text-3xl font-bold text-primary sm:text-4xl group-hover:text-primary/80 transition-all duration-500">
            {stat.value}
          </div>
          <div className="mt-2 text-sm text-muted-foreground">{stat.label}</div>
        </div>
      ))}
    </div>
  )
}

